--
-- Name: add_article_language_constraints(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.add_article_language_constraints() RETURNS void
    LANGUAGE plpgsql
    AS $$
DECLARE
    partition_record RECORD;
BEGIN
    -- Add unique constraint for slug + language_code to each existing partition
    FOR partition_record IN
        SELECT schemaname, tablename
        FROM pg_tables
        WHERE tablename LIKE 'articles_%'
        AND schemaname = 'public'
    LOOP
        BEGIN
            EXECUTE format('ALTER TABLE %I.%I ADD CONSTRAINT %I UNIQUE (slug, language_code)',
                partition_record.schemaname, 
                partition_record.tablename,
                partition_record.tablename || '_slug_language_unique');
        EXCEPTION
            WHEN duplicate_table THEN
                -- Constraint already exists, skip
                NULL;
        END;
    END LOOP;
END;
$$;


--
-- Name: aggregate_integration_metrics(character varying, character varying, interval); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.aggregate_integration_metrics(component_name character varying, metric_name character varying, time_window interval DEFAULT '01:00:00'::interval) RETURNS TABLE(avg_value numeric, min_value numeric, max_value numeric, count_values bigint)
    LANGUAGE plpgsql
    AS $$
BEGIN
    RETURN QUERY
    SELECT 
        AVG(im.metric_value) as avg_value,
        MIN(im.metric_value) as min_value,
        MAX(im.metric_value) as max_value,
        COUNT(im.metric_value) as count_values
    FROM integration_metrics im
    WHERE im.component = component_name
    AND im.metric_name = aggregate_integration_metrics.metric_name
    AND im.recorded_at >= NOW() - time_window;
END;
$$;


