--
-- Name: calculate_overall_health_score(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.calculate_overall_health_score() RETURNS numeric
    LANGUAGE plpgsql
    AS $$
DECLARE
    overall_score DECIMAL(5,2);
BEGIN
    SELECT AVG(health_score) INTO overall_score
    FROM component_health
    WHERE checked_at >= NOW() - INTERVAL '1 hour'
    AND health_score IS NOT NULL;
    
    RETURN COALESCE(overall_score, 0);
END;
$$;


