-- Name: FUNCTION cleanup_old_consistency_data(retention_days integer); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.cleanup_old_consistency_data(retention_days integer) IS 'Cleans up old consistency data beyond retention period';


--
-- Name: create_article_partition_with_language_support(text, date, date); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.create_article_partition_with_language_support(partition_name text, start_date date, end_date date) RETURNS void
    LANGUAGE plpgsql
    AS $$
BEGIN
    -- Create the partition
    EXECUTE format('CREATE TABLE %I PARTITION OF articles FOR VALUES FROM (%L) TO (%L)',
        partition_name, start_date, end_date);
    
    -- Add language-aware unique constraint
    EXECUTE format('ALTER TABLE %I ADD CONSTRAINT %I UNIQUE (slug, language_code)',
        partition_name, partition_name || '_slug_language_unique');
    
    -- Create standard indexes
    EXECUTE format('CREATE INDEX idx_%I_published_at ON %I (published_at DESC) WHERE status = ''published''',
        partition_name, partition_name);
    EXECUTE format('CREATE INDEX idx_%I_category ON %I (category_id, published_at DESC)',
        partition_name, partition_name);
    EXECUTE format('CREATE INDEX idx_%I_author ON %I (author_id, published_at DESC)',
        partition_name, partition_name);
    EXECUTE format('CREATE INDEX idx_%I_slug ON %I (slug) WHERE status = ''published''',
        partition_name, partition_name);
    EXECUTE format('CREATE INDEX idx_%I_search ON %I USING gin(to_tsvector(''english'', title || '' '' || content))',
        partition_name, partition_name);
    EXECUTE format('CREATE INDEX idx_%I_published_brin ON %I USING BRIN (published_at) WITH (pages_per_range = 128)',
        partition_name, partition_name);
    
    -- Add language-specific indexes
    EXECUTE format('CREATE INDEX idx_%I_language ON %I (language_code, published_at DESC) WHERE status = ''published''',
        partition_name, partition_name);
    EXECUTE format('CREATE INDEX idx_%I_translation_group ON %I (translation_group_id) WHERE translation_group_id IS NOT NULL',
        partition_name, partition_name);
END;
$$;


--
-- Name: create_article_tags_daily_partitions(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.create_article_tags_daily_partitions() RETURNS TABLE(partition_name text, status text, error_message text)
    LANGUAGE plpgsql
    AS $$
DECLARE
    start_date date;
    end_date date;
    part_name text;
    created_count integer := 0;
    error_count integer := 0;
BEGIN
    -- Create partitions for next 30 days
    FOR i IN 0..30 LOOP
        start_date := CURRENT_DATE + i;
        end_date := start_date + interval '1 day';
        part_name := 'article_tags_' || to_char(start_date, 'YYYY_MM_DD');
        
        -- Check if partition already exists
        IF NOT EXISTS (
            SELECT 1 FROM pg_class WHERE relname = part_name
        ) THEN
            BEGIN
                -- Create the partition
                EXECUTE format('CREATE TABLE %I PARTITION OF article_tags FOR VALUES FROM (%L) TO (%L)',
                    part_name, start_date, end_date);
                
                -- Create indexes on the partition
                EXECUTE format('CREATE INDEX idx_%I_article ON %I (article_id)',
                    part_name, part_name);
                EXECUTE format('CREATE INDEX idx_%I_tag ON %I (tag_id)',
                    part_name, part_name);
                    
                created_count := created_count + 1;
                partition_name := part_name;
                status := 'created';
                error_message := NULL;
                RETURN NEXT;
                
            EXCEPTION
                WHEN duplicate_table THEN
                    partition_name := part_name;
                    status := 'exists';
                    error_message := 'Partition already exists';
                    RETURN NEXT;
                WHEN OTHERS THEN
                    error_count := error_count + 1;
                    partition_name := part_name;
                    status := 'error';
                    error_message := SQLERRM;
                    RETURN NEXT;
            END;
        ELSE
            partition_name := part_name;
            status := 'exists';
            error_message := 'Partition already exists';
            RETURN NEXT;
        END IF;
    END LOOP;
    
    -- Return summary
    partition_name := 'SUMMARY';
    status := format('Created: %s, Errors: %s', created_count, error_count);
    error_message := NULL;
    RETURN NEXT;
END;
$$;


--
-- Name: create_article_version(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.create_article_version() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
    next_version INTEGER;
BEGIN
    -- Get next version number
    SELECT COALESCE(MAX(version_number), 0) + 1 
    INTO next_version 
    FROM article_versions 
    WHERE article_id = NEW.id;
    
    -- Insert new version record
    INSERT INTO article_versions (
        article_id, version_number, title, slug, content, excerpt,
        author_id, category_id, status, published_at,
        meta_title, meta_description, canonical_url, schema_type,
        language_code, translation_group_id, auto_linking,
        change_summary, created_by
    ) VALUES (
        NEW.id, next_version, NEW.title, NEW.slug, NEW.content, NEW.excerpt,
        NEW.author_id, NEW.category_id, NEW.status, NEW.published_at,
        NEW.meta_title, NEW.meta_description, NEW.canonical_url, NEW.schema_type,
        COALESCE(NEW.language_code, 'fa'), NEW.translation_group_id, COALESCE(NEW.auto_linking, true),
        'Automatic version created on article update', NEW.author_id
    );
    
    RETURN NEW;
END;
$$;


--
-- Name: create_daily_monitoring_partitions(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.create_daily_monitoring_partitions() RETURNS void
    LANGUAGE plpgsql
    AS $$
DECLARE
    start_date date;
    end_date date;
    table_name text;
    partition_name text;
BEGIN
    -- Create partitions for the next 14 days (gives buffer for weekends/holidays)
    FOR i IN 0..13 LOOP
        start_date := CURRENT_DATE + i;
        end_date := start_date + 1;

        -- Create partitions for each metrics table (the actual tables, not _history)
        FOREACH table_name IN ARRAY ARRAY['system_metrics', 'database_metrics', 'cache_metrics', 'publishing_metrics'] LOOP
            partition_name := table_name || '_' || to_char(start_date, 'YYYY_MM_DD');

            -- Check if partition already exists
            IF NOT EXISTS (
                SELECT 1 FROM pg_class c
                JOIN pg_namespace n ON n.oid = c.relnamespace
                WHERE c.relname = partition_name AND n.nspname = 'public'
            ) THEN
                BEGIN
                    EXECUTE format('CREATE TABLE %I PARTITION OF %I FOR VALUES FROM (%L) TO (%L)',
                        partition_name, table_name, start_date, end_date);
                    RAISE NOTICE 'Created partition: %', partition_name;
                EXCEPTION
                    WHEN duplicate_table THEN
                        -- Ignore if already exists (race condition)
                        NULL;
                    WHEN OTHERS THEN
                        RAISE WARNING 'Failed to create partition %: %', partition_name, SQLERRM;
                END;
            END IF;
        END LOOP;
    END LOOP;
END;
$$;


--
-- Name: FUNCTION create_daily_monitoring_partitions(); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.create_daily_monitoring_partitions() IS 'Creates daily partitions for metrics tables (system_metrics, database_metrics, cache_metrics, publishing_metrics). 
Should be called regularly to ensure partitions exist for upcoming dates. 
The application also creates partitions on-demand when writing metrics.';


--
-- Name: create_daily_partitions(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.create_daily_partitions() RETURNS TABLE(partition_name text, status text, error_message text)
    LANGUAGE plpgsql
    AS $$
DECLARE
    start_date date;
    end_date date;
    part_name text;
    created_count integer := 0;
    error_count integer := 0;
BEGIN
    -- Create partitions for next 7 days
    FOR i IN 0..6 LOOP
        start_date := CURRENT_DATE + i;
        end_date := start_date + interval '1 day';
        part_name := 'articles_' || to_char(start_date, 'YYYY_MM_DD');
        
        -- Check if partition already exists
        IF NOT EXISTS (
            SELECT 1 FROM pg_class WHERE relname = part_name
        ) THEN
            BEGIN
                -- Create the partition
                EXECUTE format('CREATE TABLE %I PARTITION OF articles FOR VALUES FROM (%L) TO (%L)',
                    part_name, start_date, end_date);
                
                -- Create optimized indexes for daily partitions
                EXECUTE format('CREATE INDEX idx_%I_published_at ON %I (published_at DESC) WHERE status = ''published''',
                    part_name, part_name);
                EXECUTE format('CREATE INDEX idx_%I_category ON %I (category_id, published_at DESC)',
                    part_name, part_name);
                EXECUTE format('CREATE INDEX idx_%I_author ON %I (author_id, published_at DESC)',
                    part_name, part_name);
                EXECUTE format('CREATE INDEX idx_%I_slug ON %I (slug) WHERE status = ''published''',
                    part_name, part_name);
                
                -- BRIN index for time-series performance on daily partitions
                EXECUTE format('CREATE INDEX idx_%I_published_brin ON %I USING BRIN (published_at) WITH (pages_per_range = 32)',
                    part_name, part_name);
                
                -- Full-text search index
                EXECUTE format('CREATE INDEX idx_%I_search ON %I USING gin(to_tsvector(''english'', title || '' '' || content))',
                    part_name, part_name);
                    
                created_count := created_count + 1;
                partition_name := part_name;
                status := 'created';
                error_message := NULL;
                RETURN NEXT;
                
            EXCEPTION
                WHEN duplicate_table THEN
                    partition_name := part_name;
                    status := 'exists';
                    error_message := 'Partition already exists';
                    RETURN NEXT;
                WHEN OTHERS THEN
                    error_count := error_count + 1;
                    partition_name := part_name;
                    status := 'error';
                    error_message := SQLERRM;
                    RETURN NEXT;
            END;
        ELSE
            partition_name := part_name;
            status := 'exists';
            error_message := 'Partition already exists';
            RETURN NEXT;
        END IF;
    END LOOP;
    
    -- Return summary
    partition_name := 'SUMMARY';
    status := format('Created: %s, Errors: %s', created_count, error_count);
    error_message := NULL;
    RETURN NEXT;
END;
$$;


--
-- Name: create_monthly_analytics_partitions(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.create_monthly_analytics_partitions() RETURNS void
    LANGUAGE plpgsql
    AS $$
DECLARE
    start_date date;
    end_date date;
    partition_name text;
BEGIN
    -- Create partitions for next month
    start_date := date_trunc('month', CURRENT_DATE + interval '1 month');
    end_date := start_date + interval '1 month';
    
    -- User behavior partition
    partition_name := 'user_behavior_' || to_char(start_date, 'YYYY_MM');
    EXECUTE format('CREATE TABLE IF NOT EXISTS %I PARTITION OF user_behavior FOR VALUES FROM (%L) TO (%L)',
        partition_name, start_date, end_date);
    
    EXECUTE format('CREATE INDEX IF NOT EXISTS idx_%I_session ON %I (session_id, created_at)',
        partition_name, partition_name);
    EXECUTE format('CREATE INDEX IF NOT EXISTS idx_%I_user ON %I (user_id, created_at) WHERE user_id IS NOT NULL',
        partition_name, partition_name);
    EXECUTE format('CREATE INDEX IF NOT EXISTS idx_%I_page ON %I (page_url, created_at)',
        partition_name, partition_name);
    EXECUTE format('CREATE INDEX IF NOT EXISTS idx_%I_behavior_gin ON %I USING gin(behavior_data)',
        partition_name, partition_name);
    EXECUTE format('CREATE INDEX IF NOT EXISTS idx_%I_created_brin ON %I USING BRIN (created_at) WITH (pages_per_range = 64)',
        partition_name, partition_name);
    
    -- Performance metrics partition
    partition_name := 'performance_metrics_' || to_char(start_date, 'YYYY_MM');
    EXECUTE format('CREATE TABLE IF NOT EXISTS %I PARTITION OF performance_metrics FOR VALUES FROM (%L) TO (%L)',
        partition_name, start_date, end_date);
    
    EXECUTE format('CREATE INDEX IF NOT EXISTS idx_%I_type ON %I (metric_type, created_at)',
        partition_name, partition_name);
    EXECUTE format('CREATE INDEX IF NOT EXISTS idx_%I_name ON %I (name, created_at)',
        partition_name, partition_name);
    EXECUTE format('CREATE INDEX IF NOT EXISTS idx_%I_tags_gin ON %I USING gin(tags)',
        partition_name, partition_name);
    EXECUTE format('CREATE INDEX IF NOT EXISTS idx_%I_created_brin ON %I USING BRIN (created_at) WITH (pages_per_range = 64)',
        partition_name, partition_name);
END;
$$;


--
-- Name: create_translation_group(character varying, bigint[]); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.create_translation_group(p_group_type character varying, p_content_ids bigint[]) RETURNS bigint
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_group_id BIGINT;
    v_content_id BIGINT;
BEGIN
    -- Create new translation group
    INSERT INTO translation_groups (group_type)
    VALUES (p_group_type)
    RETURNING id INTO v_group_id;
    
    -- Link content to the group
    FOREACH v_content_id IN ARRAY p_content_ids
    LOOP
        CASE p_group_type
            WHEN 'article' THEN
                UPDATE articles SET translation_group_id = v_group_id WHERE id = v_content_id;
            WHEN 'category' THEN
                UPDATE categories SET translation_group_id = v_group_id WHERE id = v_content_id;
            WHEN 'tag' THEN
                UPDATE tags SET translation_group_id = v_group_id WHERE id = v_content_id;
        END CASE;
    END LOOP;
    
    RETURN v_group_id;
END;
$$;


--
-- Name: drop_old_monitoring_partitions(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.drop_old_monitoring_partitions() RETURNS void
    LANGUAGE plpgsql
    AS $$
DECLARE
    table_name TEXT;
    partition_date DATE;
    partition_name TEXT;
    retention_days INTEGER := 30; -- Keep 30 days of data
BEGIN
    FOREACH table_name IN ARRAY ARRAY['system_metrics', 'database_metrics', 'cache_metrics', 'publishing_metrics']
    LOOP
        partition_date := CURRENT_DATE - retention_days;
        partition_name := table_name || '_' || TO_CHAR(partition_date, 'YYYY_MM_DD');
        
        -- Check if partition exists and drop it
        IF EXISTS (
            SELECT 1 FROM pg_class c 
            JOIN pg_namespace n ON n.oid = c.relnamespace 
            WHERE c.relname = partition_name AND n.nspname = 'public'
        ) THEN
            EXECUTE format('DROP TABLE IF EXISTS %I', partition_name);
        END IF;
    END LOOP;
END;
$$;


--
-- Name: drop_old_partitions(integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.drop_old_partitions(retention_days integer DEFAULT 30) RETURNS TABLE(partition_name text, status text, error_message text)
    LANGUAGE plpgsql
    AS $_$
DECLARE
    partition_record RECORD;
    cutoff_date date;
    dropped_count integer := 0;
    error_count integer := 0;
BEGIN
    cutoff_date := CURRENT_DATE - retention_days;
    
    -- Find and drop old article partitions
    FOR partition_record IN
        SELECT schemaname, tablename 
        FROM pg_tables 
        WHERE tablename ~ '^articles_\d{4}_\d{2}(_\d{2})?$'
        AND schemaname = 'public'
    LOOP
        -- Extract date from partition name and check if it's old enough
        DECLARE
            partition_date date;
            date_part text;
        BEGIN
            -- Extract date part from partition name (articles_YYYY_MM or articles_YYYY_MM_DD)
            date_part := regexp_replace(partition_record.tablename, '^articles_', '');
            
            -- Handle both monthly (YYYY_MM) and daily (YYYY_MM_DD) partitions
            IF date_part ~ '^\d{4}_\d{2}_\d{2}$' THEN
                -- Daily partition format
                partition_date := to_date(date_part, 'YYYY_MM_DD');
            ELSIF date_part ~ '^\d{4}_\d{2}$' THEN
                -- Monthly partition format - use first day of month
                partition_date := to_date(date_part || '_01', 'YYYY_MM_DD');
            ELSE
                CONTINUE; -- Skip if format doesn't match
            END IF;
            
            IF partition_date < cutoff_date THEN
                BEGIN
                    EXECUTE format('DROP TABLE IF EXISTS %I.%I CASCADE',
                        partition_record.schemaname, partition_record.tablename);
                    dropped_count := dropped_count + 1;
                    partition_name := partition_record.tablename;
                    status := 'dropped';
                    error_message := NULL;
                    RETURN NEXT;
                EXCEPTION
                    WHEN OTHERS THEN
                        error_count := error_count + 1;
                        partition_name := partition_record.tablename;
                        status := 'error';
                        error_message := SQLERRM;
                        RETURN NEXT;
                END;
            END IF;
        EXCEPTION
            WHEN OTHERS THEN
                error_count := error_count + 1;
                partition_name := partition_record.tablename;
                status := 'error';
                error_message := 'Failed to process partition: ' || SQLERRM;
                RETURN NEXT;
        END;
    END LOOP;
    
    -- Drop old article_tags partitions
    FOR partition_record IN
        SELECT schemaname, tablename 
        FROM pg_tables 
        WHERE tablename ~ '^article_tags_\d{4}_\d{2}$'
        AND schemaname = 'public'
    LOOP
        DECLARE
            partition_date date;
            date_part text;
        BEGIN
            date_part := regexp_replace(partition_record.tablename, '^article_tags_', '');
            partition_date := to_date(date_part || '_01', 'YYYY_MM_DD');
            
            IF partition_date < cutoff_date THEN
                BEGIN
                    EXECUTE format('DROP TABLE IF EXISTS %I.%I CASCADE',
                        partition_record.schemaname, partition_record.tablename);
                    dropped_count := dropped_count + 1;
                    partition_name := partition_record.tablename;
                    status := 'dropped';
                    error_message := NULL;
                    RETURN NEXT;
                EXCEPTION
                    WHEN OTHERS THEN
                        error_count := error_count + 1;
                        partition_name := partition_record.tablename;
                        status := 'error';
                        error_message := SQLERRM;
                        RETURN NEXT;
                END;
            END IF;
        EXCEPTION
            WHEN OTHERS THEN
                error_count := error_count + 1;
                partition_name := partition_record.tablename;
                status := 'error';
                error_message := 'Failed to process article_tags partition: ' || SQLERRM;
                RETURN NEXT;
        END;
    END LOOP;
    
    -- Drop old article_views partitions
    FOR partition_record IN
        SELECT schemaname, tablename 
        FROM pg_tables 
        WHERE tablename ~ '^article_views_\d{4}_\d{2}$'
        AND schemaname = 'public'
    LOOP
        DECLARE
            partition_date date;
            date_part text;
        BEGIN
            date_part := regexp_replace(partition_record.tablename, '^article_views_', '');
            partition_date := to_date(date_part || '_01', 'YYYY_MM_DD');
            
            IF partition_date < cutoff_date THEN
                BEGIN
                    EXECUTE format('DROP TABLE IF EXISTS %I.%I CASCADE',
                        partition_record.schemaname, partition_record.tablename);
                    dropped_count := dropped_count + 1;
                    partition_name := partition_record.tablename;
                    status := 'dropped';
                    error_message := NULL;
                    RETURN NEXT;
                EXCEPTION
                    WHEN OTHERS THEN
                        error_count := error_count + 1;
                        partition_name := partition_record.tablename;
                        status := 'error';
                        error_message := SQLERRM;
                        RETURN NEXT;
                END;
            END IF;
        EXCEPTION
            WHEN OTHERS THEN
                error_count := error_count + 1;
                partition_name := partition_record.tablename;
                status := 'error';
                error_message := 'Failed to process article_views partition: ' || SQLERRM;
                RETURN NEXT;
        END;
    END LOOP;
    
    -- Return summary
    partition_name := 'SUMMARY';
    status := format('Dropped: %s, Errors: %s', dropped_count, error_count);
    error_message := NULL;
    RETURN NEXT;
END;
$_$;


--
-- Name: generate_canonical_url(character varying, bigint, character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.generate_canonical_url(target_type character varying, target_id bigint DEFAULT NULL::bigint, target_url character varying DEFAULT NULL::character varying) RETURNS character varying
    LANGUAGE plpgsql
    AS $$
DECLARE
    result_url VARCHAR(500);
    tag_slug VARCHAR(100);
    category_slug VARCHAR(100);
    category_path TEXT;
BEGIN
    CASE target_type
        WHEN 'tag' THEN
            SELECT slug INTO tag_slug FROM tags WHERE id = target_id;
            IF tag_slug IS NULL THEN
                RAISE EXCEPTION 'Tag with ID % not found', target_id;
            END IF;
            result_url := '/tag/' || tag_slug;
            
        WHEN 'category' THEN
            -- Build category path for hierarchical categories
            WITH RECURSIVE category_hierarchy AS (
                SELECT id, slug, parent_id, slug as path
                FROM categories 
                WHERE id = target_id
                
                UNION ALL
                
                SELECT c.id, c.slug, c.parent_id, c.slug || '/' || ch.path
                FROM categories c
                INNER JOIN category_hierarchy ch ON c.id = ch.parent_id
            )
            SELECT path INTO category_path 
            FROM category_hierarchy 
            WHERE parent_id IS NULL;
            
            IF category_path IS NULL THEN
                RAISE EXCEPTION 'Category with ID % not found', target_id;
            END IF;
            result_url := '/category/' || category_path;
            
        WHEN 'url' THEN
            IF target_url IS NULL OR target_url = '' THEN
                RAISE EXCEPTION 'Custom URL cannot be empty';
            END IF;
            result_url := target_url;
            
        ELSE
            RAISE EXCEPTION 'Invalid target_type: %', target_type;
    END CASE;
    
    RETURN result_url;
END;
$$;


--
-- Name: FUNCTION generate_canonical_url(target_type character varying, target_id bigint, target_url character varying); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.generate_canonical_url(target_type character varying, target_id bigint, target_url character varying) IS 'Generates canonical URLs for tags, categories, or custom URLs';


