--
-- Name: get_articles_by_language(character varying, character varying, integer, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_articles_by_language(p_language_code character varying, p_fallback_language character varying DEFAULT 'en'::character varying, p_limit integer DEFAULT 20, p_offset integer DEFAULT 0) RETURNS TABLE(id bigint, title character varying, slug character varying, excerpt text, language_code character varying, published_at timestamp with time zone, is_fallback boolean)
    LANGUAGE plpgsql
    AS $$
BEGIN
    RETURN QUERY
    WITH language_articles AS (
        -- Get articles in requested language
        SELECT a.id, a.title, a.slug, a.excerpt, a.language_code, a.published_at, false as is_fallback
        FROM articles a
        WHERE a.language_code = p_language_code 
        AND a.status = 'published'
        ORDER BY a.published_at DESC
        LIMIT p_limit OFFSET p_offset
    ),
    fallback_articles AS (
        -- Get fallback articles for missing content
        SELECT a.id, a.title, a.slug, a.excerpt, a.language_code, a.published_at, true as is_fallback
        FROM articles a
        WHERE a.language_code = p_fallback_language 
        AND a.status = 'published'
        AND NOT EXISTS (
            SELECT 1 FROM language_articles la WHERE la.id = a.id
        )
        ORDER BY a.published_at DESC
        LIMIT (p_limit - (SELECT COUNT(*) FROM language_articles))
    )
    SELECT * FROM language_articles
    UNION ALL
    SELECT * FROM fallback_articles
    ORDER BY published_at DESC;
END;
$$;


