-- Name: FUNCTION get_articles_by_language(p_language_code character varying, p_fallback_language character varying, p_limit integer, p_offset integer); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.get_articles_by_language(p_language_code character varying, p_fallback_language character varying, p_limit integer, p_offset integer) IS 'Get articles by language with English fallback';


--
-- Name: get_backup_health(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_backup_health() RETURNS jsonb
    LANGUAGE plpgsql
    AS $$
DECLARE
    result JSONB;
    recent_backup_count INTEGER;
    failed_backup_count INTEGER;
    last_successful_backup TIMESTAMP WITH TIME ZONE;
BEGIN
    -- Check for recent successful backups (last 48 hours)
    SELECT COUNT(*) INTO recent_backup_count
    FROM backups 
    WHERE status = 'completed' 
    AND created_at > NOW() - INTERVAL '48 hours';
    
    -- Check for recent failed backups (last 24 hours)
    SELECT COUNT(*) INTO failed_backup_count
    FROM backups 
    WHERE status = 'failed' 
    AND created_at > NOW() - INTERVAL '24 hours';
    
    -- Get last successful backup time
    SELECT MAX(completed_at) INTO last_successful_backup
    FROM backups 
    WHERE status = 'completed';
    
    -- Build result JSON
    result := jsonb_build_object(
        'healthy', CASE 
            WHEN recent_backup_count > 0 AND failed_backup_count = 0 THEN true 
            ELSE false 
        END,
        'recent_successful_backups', recent_backup_count,
        'recent_failed_backups', failed_backup_count,
        'last_successful_backup', last_successful_backup,
        'check_time', NOW()
    );
    
    RETURN result;
END;
$$;


--
-- Name: get_consistency_health_score(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_consistency_health_score() RETURNS TABLE(overall_score numeric, total_issues integer, high_severity_issues integer, resolved_rate numeric, avg_resolution_time_hours numeric)
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_total_issues INTEGER;
    v_high_severity_issues INTEGER;
    v_resolved_issues INTEGER;
    v_avg_resolution_hours DECIMAL(10,2);
    v_overall_score DECIMAL(5,2);
    v_resolved_rate DECIMAL(5,2);
BEGIN
    -- Get issue counts from last 30 days
    SELECT 
        COUNT(*),
        COUNT(*) FILTER (WHERE severity = 'high'),
        COUNT(*) FILTER (WHERE status = 'resolved')
    INTO v_total_issues, v_high_severity_issues, v_resolved_issues
    FROM consistency_issues
    WHERE created_at >= CURRENT_DATE - INTERVAL '30 days';
    
    -- Calculate resolved rate
    IF v_total_issues > 0 THEN
        v_resolved_rate := (v_resolved_issues::DECIMAL / v_total_issues) * 100;
    ELSE
        v_resolved_rate := 100.0;
    END IF;
    
    -- Calculate average resolution time
    SELECT AVG(EXTRACT(EPOCH FROM (resolved_at - created_at)) / 3600)
    INTO v_avg_resolution_hours
    FROM consistency_issues
    WHERE status = 'resolved' 
    AND resolved_at IS NOT NULL
    AND created_at >= CURRENT_DATE - INTERVAL '30 days';
    
    -- Calculate overall health score (0-100)
    v_overall_score := GREATEST(0, 
        100 - 
        (v_high_severity_issues * 10) - 
        (GREATEST(0, v_total_issues - 50) * 0.5) -
        (CASE WHEN v_resolved_rate < 80 THEN (80 - v_resolved_rate) * 0.5 ELSE 0 END)
    );
    
    RETURN QUERY SELECT 
        v_overall_score,
        v_total_issues,
        v_high_severity_issues,
        v_resolved_rate,
        COALESCE(v_avg_resolution_hours, 0.0);
END;
$$;


--
-- Name: FUNCTION get_consistency_health_score(); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.get_consistency_health_score() IS 'Calculates overall consistency health score (0-100)';


