    -- Log maintenance completion
    RAISE NOTICE 'Partition maintenance completed at %', NOW();
END;
$$;


--
-- Name: process_canonical_job(bigint, bigint); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.process_canonical_job(job_id bigint, processor_user_id bigint DEFAULT NULL::bigint) RETURNS boolean
    LANGUAGE plpgsql
    AS $$
DECLARE
    job_record RECORD;
    canonical_url VARCHAR(500);
    article_partition_name TEXT;
BEGIN
    -- Lock and fetch the job
    SELECT * INTO job_record 
    FROM canonical_jobs 
    WHERE id = job_id AND status = 'pending'
    FOR UPDATE SKIP LOCKED;
    
    IF NOT FOUND THEN
        RETURN FALSE; -- Job not found or already processed
    END IF;
    
    -- Check if it's time to process (unless admin override)
    IF NOT job_record.admin_override AND job_record.scheduled_at > NOW() THEN
        RETURN FALSE; -- Not yet time to process
    END IF;
    
    BEGIN
        -- Generate canonical URL
        canonical_url := generate_canonical_url(
            job_record.target_type, 
            job_record.target_id, 
            job_record.target_url
        );
        
        -- Update the article's canonical URL
        -- Note: We need to update across all partitions since we don't know which partition contains the article
        UPDATE articles 
        SET canonical_url = canonical_url, updated_at = NOW()
        WHERE id = job_record.article_id;
        
        -- Mark job as processed
        UPDATE canonical_jobs 
        SET status = 'processed',
            processed_at = NOW(),
            processed_by = processor_user_id,
            updated_at = NOW()
        WHERE id = job_id;
        
        RETURN TRUE;
        
    EXCEPTION WHEN OTHERS THEN
        -- Mark job as failed and increment retry count
        UPDATE canonical_jobs 
        SET status = 'failed',
            error_message = SQLERRM,
            retry_count = retry_count + 1,
            updated_at = NOW()
        WHERE id = job_id;
        
        RETURN FALSE;
    END;
END;
$$;


--
-- Name: FUNCTION process_canonical_job(job_id bigint, processor_user_id bigint); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.process_canonical_job(job_id bigint, processor_user_id bigint) IS 'Processes a single canonical job and updates the article';


--
-- Name: schedule_canonical_job(bigint, character varying, bigint, character varying, bigint, boolean); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.schedule_canonical_job(p_article_id bigint, p_target_type character varying, p_target_id bigint DEFAULT NULL::bigint, p_target_url character varying DEFAULT NULL::character varying, p_created_by bigint DEFAULT NULL::bigint, p_admin_override boolean DEFAULT false) RETURNS bigint
    LANGUAGE plpgsql
    AS $$
DECLARE
    job_id BIGINT;
    scheduled_time TIMESTAMP WITH TIME ZONE;
BEGIN
    -- Calculate scheduled time (48 hours from now, or immediate if admin override)
    IF p_admin_override THEN
        scheduled_time := NOW();
    ELSE
        scheduled_time := NOW() + INTERVAL '48 hours';
    END IF;
    
    -- Validate target parameters
    IF p_target_type IN ('tag', 'category') AND p_target_id IS NULL THEN
        RAISE EXCEPTION 'target_id is required for target_type %', p_target_type;
    END IF;
    
    IF p_target_type = 'url' AND (p_target_url IS NULL OR p_target_url = '') THEN
        RAISE EXCEPTION 'target_url is required for target_type url';
    END IF;
    
    -- Cancel any existing pending jobs for this article
    UPDATE canonical_jobs 
    SET status = 'cancelled', updated_at = NOW()
    WHERE article_id = p_article_id AND status = 'pending';
    
    -- Insert new job
    INSERT INTO canonical_jobs (
        article_id, target_type, target_id, target_url, 
        scheduled_at, admin_override, created_by
    ) VALUES (
        p_article_id, p_target_type, p_target_id, p_target_url,
        scheduled_time, p_admin_override, p_created_by
    ) RETURNING id INTO job_id;
    
    RETURN job_id;
END;
$$;


--
-- Name: FUNCTION schedule_canonical_job(p_article_id bigint, p_target_type character varying, p_target_id bigint, p_target_url character varying, p_created_by bigint, p_admin_override boolean); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.schedule_canonical_job(p_article_id bigint, p_target_type character varying, p_target_id bigint, p_target_url character varying, p_created_by bigint, p_admin_override boolean) IS 'Schedules a new canonical job with 48-hour delay or immediate processing';


