--
-- Name: validate_tag_keyword_uniqueness(jsonb, bigint); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.validate_tag_keyword_uniqueness(p_keywords jsonb, p_exclude_tag_id bigint DEFAULT NULL::bigint) RETURNS boolean
    LANGUAGE plpgsql
    AS $$
DECLARE
    keyword_text TEXT;
    existing_tag_name TEXT;
BEGIN
    -- Check each keyword against existing tags
    FOR keyword_text IN SELECT jsonb_array_elements_text(p_keywords) LOOP
        -- Normalize the keyword (lowercase, trimmed)
        keyword_text := LOWER(TRIM(keyword_text));
        
        -- Skip empty keywords
        IF keyword_text = '' THEN
            CONTINUE;
        END IF;
        
        -- Check if this keyword exists in any other tag
        SELECT t.name INTO existing_tag_name
        FROM tags t
        WHERE t.id != COALESCE(p_exclude_tag_id, 0)
          AND t.keywords ? keyword_text;
        
        -- If found, return false (not unique)
        IF existing_tag_name IS NOT NULL THEN
            RAISE EXCEPTION 'Keyword "%" is already used by tag "%"', keyword_text, existing_tag_name;
        END IF;
    END LOOP;
    
    RETURN TRUE;
END;
$$;


--
-- Name: FUNCTION validate_tag_keyword_uniqueness(p_keywords jsonb, p_exclude_tag_id bigint); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.validate_tag_keyword_uniqueness(p_keywords jsonb, p_exclude_tag_id bigint) IS 'Validates that keywords are unique across all tags. Used for Task 8 keyword validation.';


