SET default_table_access_method = heap;

--
-- Name: alert_history; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.alert_history (
    id bigint NOT NULL,
    name character varying(255) NOT NULL,
    description text,
    severity character varying(20) NOT NULL,
    status character varying(20) NOT NULL,
    component character varying(100) NOT NULL,
    metric character varying(100) NOT NULL,
    threshold numeric(10,2),
    current_value numeric(10,2),
    metadata jsonb DEFAULT '{}'::jsonb,
    triggered_at timestamp with time zone NOT NULL,
    resolved_at timestamp with time zone,
    created_at timestamp with time zone DEFAULT now(),
    updated_at timestamp with time zone DEFAULT now(),
    CONSTRAINT alert_history_severity_check CHECK (((severity)::text = ANY ((ARRAY['info'::character varying, 'warning'::character varying, 'critical'::character varying])::text[]))),
    CONSTRAINT alert_history_status_check CHECK (((status)::text = ANY ((ARRAY['active'::character varying, 'resolved'::character varying, 'suppressed'::character varying])::text[])))
);


--
-- Name: active_alerts; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.active_alerts AS
 SELECT alert_history.id,
    alert_history.name,
    alert_history.description,
    alert_history.severity,
    alert_history.status,
    alert_history.component,
    alert_history.metric,
    alert_history.threshold,
    alert_history.current_value,
    alert_history.metadata,
    alert_history.triggered_at,
    alert_history.resolved_at,
    alert_history.created_at,
    alert_history.updated_at
   FROM public.alert_history
  WHERE ((alert_history.status)::text = 'active'::text)
  ORDER BY alert_history.triggered_at DESC;


--
-- Name: system_alerts; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.system_alerts (
    id integer NOT NULL,
    alert_id character varying(100) NOT NULL,
    alert_type character varying(50) NOT NULL,
    severity character varying(20) NOT NULL,
    component character varying(100),
    message text NOT NULL,
    details jsonb,
    status character varying(20) DEFAULT 'active'::character varying,
    created_at timestamp without time zone DEFAULT now(),
    acknowledged_at timestamp without time zone,
    resolved_at timestamp without time zone,
    CONSTRAINT chk_system_alerts_severity CHECK (((severity)::text = ANY ((ARRAY['low'::character varying, 'medium'::character varying, 'high'::character varying, 'critical'::character varying])::text[]))),
    CONSTRAINT chk_system_alerts_status CHECK (((status)::text = ANY ((ARRAY['active'::character varying, 'acknowledged'::character varying, 'resolved'::character varying, 'suppressed'::character varying])::text[])))
);


--
-- Name: TABLE system_alerts; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON TABLE public.system_alerts IS 'Manages system alerts and notifications';


--
-- Name: active_alerts_summary; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.active_alerts_summary AS
 SELECT system_alerts.alert_type,
    system_alerts.severity,
    system_alerts.component,
    count(*) AS alert_count,
    min(system_alerts.created_at) AS oldest_alert,
    max(system_alerts.created_at) AS newest_alert
   FROM public.system_alerts
  WHERE ((system_alerts.status)::text = 'active'::text)
  GROUP BY system_alerts.alert_type, system_alerts.severity, system_alerts.component
  ORDER BY
        CASE system_alerts.severity
            WHEN 'critical'::text THEN 1
            WHEN 'high'::text THEN 2
            WHEN 'medium'::text THEN 3
            WHEN 'low'::text THEN 4
            ELSE NULL::integer
        END, (count(*)) DESC;


--
-- Name: VIEW active_alerts_summary; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON VIEW public.active_alerts_summary IS 'Summarizes active alerts by type and severity';


