--
-- Name: articles; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.articles (
    id bigint NOT NULL,
    title character varying(255) NOT NULL,
    slug character varying(255) NOT NULL,
    content text NOT NULL,
    excerpt text,
    author_id bigint NOT NULL,
    category_id bigint NOT NULL,
    status character varying(20) DEFAULT 'draft'::character varying,
    published_at timestamp with time zone NOT NULL,
    created_at timestamp with time zone DEFAULT now(),
    updated_at timestamp with time zone DEFAULT now(),
    view_count bigint DEFAULT 0,
    like_count bigint DEFAULT 0,
    dislike_count bigint DEFAULT 0,
    meta_title character varying(60),
    meta_description character varying(160),
    canonical_url character varying(500),
    schema_type character varying(50) DEFAULT 'NewsArticle'::character varying,
    auto_linking boolean DEFAULT true,
    language_code character varying(5) DEFAULT 'fa'::character varying NOT NULL,
    translation_group_id bigint,
    moderation_status character varying(20) DEFAULT 'approved'::character varying,
    moderation_notes text,
    last_moderated_at timestamp with time zone,
    last_moderated_by bigint,
    featured_image_id bigint,
    focus_keyword character varying(100)
)
PARTITION BY RANGE (published_at);


--
-- Name: COLUMN articles.like_count; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.articles.like_count IS 'Number of likes for this article';


--
-- Name: COLUMN articles.dislike_count; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.articles.dislike_count IS 'Number of dislikes for this article';


--
-- Name: COLUMN articles.language_code; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.articles.language_code IS 'Language code (fa=Persian, en=English, ar=Arabic)';


--
-- Name: COLUMN articles.translation_group_id; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.articles.translation_group_id IS 'Links articles that are translations of each other';


--
-- Name: COLUMN articles.featured_image_id; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.articles.featured_image_id IS 'Reference to the featured image for this article';


--
-- Name: COLUMN articles.focus_keyword; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.articles.focus_keyword IS 'Primary SEO keyword for this article';


--
-- Name: languages; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.languages (
    code character varying(5) NOT NULL,
    name character varying(50) NOT NULL,
    native_name character varying(50) NOT NULL,
    direction character varying(3) NOT NULL,
    is_active boolean DEFAULT true,
    sort_order integer DEFAULT 0,
    created_at timestamp with time zone DEFAULT now(),
    CONSTRAINT languages_direction_check CHECK (((direction)::text = ANY ((ARRAY['ltr'::character varying, 'rtl'::character varying])::text[])))
);


--
-- Name: TABLE languages; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON TABLE public.languages IS 'Supported languages with RTL/LTR direction information';


--
-- Name: translation_groups; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.translation_groups (
    id bigint NOT NULL,
    group_type character varying(20) NOT NULL,
    created_at timestamp with time zone DEFAULT now(),
    updated_at timestamp with time zone DEFAULT now(),
    CONSTRAINT translation_groups_group_type_check CHECK (((group_type)::text = ANY ((ARRAY['article'::character varying, 'category'::character varying, 'tag'::character varying])::text[])))
);


--
-- Name: TABLE translation_groups; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON TABLE public.translation_groups IS 'Groups for managing translations of articles, categories, and tags';


--
-- Name: article_translations; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.article_translations AS
 SELECT a.id,
    a.title,
    a.slug,
    a.language_code,
    a.translation_group_id,
    a.published_at,
    a.status,
    tg.group_type,
    l.name AS language_name,
    l.native_name AS language_native_name,
    l.direction AS language_direction,
    array_agg(json_build_object('id', ta.id, 'title', ta.title, 'slug', ta.slug, 'language_code', ta.language_code, 'language_name', tl.name, 'language_native_name', tl.native_name) ORDER BY tl.sort_order) FILTER (WHERE (ta.id <> a.id)) AS translations
   FROM ((((public.articles a
     LEFT JOIN public.translation_groups tg ON ((a.translation_group_id = tg.id)))
     LEFT JOIN public.languages l ON (((a.language_code)::text = (l.code)::text)))
     LEFT JOIN public.articles ta ON ((a.translation_group_id = ta.translation_group_id)))
     LEFT JOIN public.languages tl ON (((ta.language_code)::text = (tl.code)::text)))
  WHERE ((a.status)::text = 'published'::text)
  GROUP BY a.id, a.title, a.slug, a.language_code, a.translation_group_id, a.published_at, a.status, tg.group_type, l.name, l.native_name, l.direction;


--
-- Name: VIEW article_translations; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON VIEW public.article_translations IS 'Articles with their available translations';


