--
-- Name: backups; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.backups (
    id bigint NOT NULL,
    type character varying(20) NOT NULL,
    status character varying(20) DEFAULT 'pending'::character varying NOT NULL,
    file_path character varying(500) NOT NULL,
    file_size bigint DEFAULT 0,
    checksum character varying(64),
    compressed boolean DEFAULT false,
    encrypted boolean DEFAULT false,
    started_at timestamp with time zone NOT NULL,
    completed_at timestamp with time zone,
    error_msg text,
    metadata jsonb,
    created_at timestamp with time zone DEFAULT now(),
    updated_at timestamp with time zone DEFAULT now(),
    CONSTRAINT backups_status_check CHECK (((status)::text = ANY ((ARRAY['pending'::character varying, 'running'::character varying, 'completed'::character varying, 'failed'::character varying, 'validated'::character varying, 'replicated'::character varying])::text[]))),
    CONSTRAINT backups_type_check CHECK (((type)::text = ANY ((ARRAY['full'::character varying, 'incremental'::character varying, 'wal'::character varying])::text[])))
);


--
-- Name: TABLE backups; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON TABLE public.backups IS 'Main backup records table for disaster recovery system';


--
-- Name: backup_metrics_view; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.backup_metrics_view AS
 SELECT count(*) AS total_backups,
    count(
        CASE
            WHEN ((backups.status)::text = 'completed'::text) THEN 1
            ELSE NULL::integer
        END) AS successful_backups,
    count(
        CASE
            WHEN ((backups.status)::text = 'failed'::text) THEN 1
            ELSE NULL::integer
        END) AS failed_backups,
    COALESCE(sum(backups.file_size), (0)::numeric) AS total_backup_size,
    COALESCE(avg((EXTRACT(epoch FROM (backups.completed_at - backups.started_at)) * (1000)::numeric)), (0)::numeric) AS average_backup_time,
    max(backups.completed_at) AS last_backup_time,
    max(
        CASE
            WHEN ((backups.status)::text = 'completed'::text) THEN backups.completed_at
            ELSE NULL::timestamp with time zone
        END) AS last_successful_backup
   FROM public.backups;


