--
-- Name: category_translations; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.category_translations AS
 SELECT c.id,
    c.name,
    c.slug,
    c.language_code,
    c.translation_group_id,
    c.parent_id,
    c.sort_order,
    l.name AS language_name,
    l.native_name AS language_native_name,
    l.direction AS language_direction,
    array_agg(json_build_object('id', tc.id, 'name', tc.name, 'slug', tc.slug, 'language_code', tc.language_code, 'language_name', tl.name, 'language_native_name', tl.native_name) ORDER BY tl.sort_order) FILTER (WHERE (tc.id <> c.id)) AS translations
   FROM ((((public.categories c
     LEFT JOIN public.translation_groups tg ON ((c.translation_group_id = tg.id)))
     LEFT JOIN public.languages l ON (((c.language_code)::text = (l.code)::text)))
     LEFT JOIN public.categories tc ON ((c.translation_group_id = tc.translation_group_id)))
     LEFT JOIN public.languages tl ON (((tc.language_code)::text = (tl.code)::text)))
  GROUP BY c.id, c.name, c.slug, c.language_code, c.translation_group_id, c.parent_id, c.sort_order, l.name, l.native_name, l.direction;


--
-- Name: VIEW category_translations; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON VIEW public.category_translations IS 'Categories with their available translations';


