--
-- Name: comment_stats; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.comment_stats AS
 SELECT comments.article_id,
    count(*) AS total_comments,
    count(
        CASE
            WHEN ((comments.status)::text = 'approved'::text) THEN 1
            ELSE NULL::integer
        END) AS approved_comments,
    count(
        CASE
            WHEN ((comments.status)::text = 'pending'::text) THEN 1
            ELSE NULL::integer
        END) AS pending_comments,
    count(
        CASE
            WHEN ((comments.status)::text = 'rejected'::text) THEN 1
            ELSE NULL::integer
        END) AS rejected_comments,
    count(
        CASE
            WHEN (comments.spam_score > 0.5) THEN 1
            ELSE NULL::integer
        END) AS spam_comments,
    max(comments.created_at) AS last_comment_at
   FROM public.comments
  GROUP BY comments.article_id;


