    id integer NOT NULL,
    component_name character varying(100) NOT NULL,
    health_status character varying(20) NOT NULL,
    health_score numeric(5,2),
    error_count integer DEFAULT 0,
    last_error text,
    metrics jsonb,
    checked_at timestamp without time zone DEFAULT now(),
    CONSTRAINT chk_component_health_score CHECK (((health_score >= (0)::numeric) AND (health_score <= (100)::numeric))),
    CONSTRAINT chk_component_health_status CHECK (((health_status)::text = ANY ((ARRAY['healthy'::character varying, 'degraded'::character varying, 'unhealthy'::character varying, 'unknown'::character varying])::text[])))
);


--
-- Name: TABLE component_health; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON TABLE public.component_health IS 'Tracks health status of system components';


--
-- Name: component_health_dashboard; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.component_health_dashboard AS
 SELECT component_health.component_name,
    component_health.health_status,
    component_health.health_score,
    component_health.error_count,
    component_health.last_error,
    component_health.checked_at,
        CASE
            WHEN (component_health.checked_at >= (now() - '00:05:00'::interval)) THEN 'current'::text
            WHEN (component_health.checked_at >= (now() - '01:00:00'::interval)) THEN 'recent'::text
            ELSE 'stale'::text
        END AS freshness
   FROM public.component_health
  WHERE (component_health.checked_at >= (now() - '24:00:00'::interval));


--
-- Name: VIEW component_health_dashboard; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON VIEW public.component_health_dashboard IS 'Provides current component health status for dashboards';


