CREATE TABLE public.consistency_check_results (
    id character varying(50) NOT NULL,
    schedule_id character varying(50),
    check_id character varying(50),
    status character varying(20) NOT NULL,
    issues_found integer DEFAULT 0,
    duration_ms bigint,
    sample_size integer,
    metadata jsonb,
    error_message text,
    created_at timestamp with time zone DEFAULT now(),
    CONSTRAINT consistency_check_results_status_check CHECK (((status)::text = ANY ((ARRAY['passed'::character varying, 'warning'::character varying, 'failed'::character varying])::text[])))
);


--
-- Name: TABLE consistency_check_results; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON TABLE public.consistency_check_results IS 'Results of scheduled consistency validation runs';


--
-- Name: consistency_schedules; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.consistency_schedules (
    id character varying(50) NOT NULL,
    name character varying(100) NOT NULL,
    cron_expression character varying(50),
    interval_seconds integer,
    enabled boolean DEFAULT true,
    sample_size integer DEFAULT 1000,
    check_types jsonb,
    last_run timestamp with time zone,
    next_run timestamp with time zone,
    created_at timestamp with time zone DEFAULT now(),
    updated_at timestamp with time zone DEFAULT now(),
    CONSTRAINT check_schedule_timing CHECK ((((cron_expression IS NOT NULL) AND (interval_seconds IS NULL)) OR ((cron_expression IS NULL) AND (interval_seconds IS NOT NULL))))
);


--
-- Name: TABLE consistency_schedules; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON TABLE public.consistency_schedules IS 'Schedules for automated consistency checks';


--
-- Name: consistency_check_performance; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.consistency_check_performance AS
 SELECT cs.name AS schedule_name,
    cs.enabled,
    cs.sample_size,
    cs.last_run,
    ccr.status AS last_status,
    ccr.issues_found AS last_issues_found,
    ccr.duration_ms AS last_duration_ms,
    avg(ccr.duration_ms) OVER (PARTITION BY cs.id ORDER BY ccr.created_at ROWS BETWEEN 9 PRECEDING AND CURRENT ROW) AS avg_duration_ms,
    avg(ccr.issues_found) OVER (PARTITION BY cs.id ORDER BY ccr.created_at ROWS BETWEEN 9 PRECEDING AND CURRENT ROW) AS avg_issues_found
   FROM (public.consistency_schedules cs
     LEFT JOIN LATERAL ( SELECT consistency_check_results.status,
            consistency_check_results.issues_found,
            consistency_check_results.duration_ms,
            consistency_check_results.created_at
           FROM public.consistency_check_results
          WHERE ((consistency_check_results.schedule_id)::text = (cs.id)::text)
          ORDER BY consistency_check_results.created_at DESC
         LIMIT 1) ccr ON (true))
  ORDER BY cs.name;


--
-- Name: VIEW consistency_check_performance; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON VIEW public.consistency_check_performance IS 'Performance metrics for scheduled consistency checks';


