--

COMMENT ON TABLE public.remediation_suggestions IS 'Automated suggestions for fixing consistency issues';


--
-- Name: consistency_dashboard; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.consistency_dashboard AS
 SELECT ci.type AS issue_type,
    ci.severity,
    count(*) AS total_issues,
    count(*) FILTER (WHERE ((ci.status)::text = 'open'::text)) AS open_issues,
    count(*) FILTER (WHERE ((ci.status)::text = 'resolved'::text)) AS resolved_issues,
    count(rs.id) AS suggestions_count,
    count(rs.id) FILTER (WHERE (rs.executed = true)) AS executed_suggestions,
    count(mrq.id) AS manual_review_count,
    count(mrq.id) FILTER (WHERE ((mrq.status)::text = 'pending'::text)) AS pending_review,
    max(ci.created_at) AS last_occurrence
   FROM ((public.consistency_issues ci
     LEFT JOIN public.remediation_suggestions rs ON (((ci.id)::text = (rs.issue_id)::text)))
     LEFT JOIN public.manual_review_queue mrq ON (((ci.id)::text = (mrq.issue_id)::text)))
  WHERE (ci.created_at >= (CURRENT_DATE - '30 days'::interval))
  GROUP BY ci.type, ci.severity
  ORDER BY (count(*)) DESC;


--
-- Name: VIEW consistency_dashboard; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON VIEW public.consistency_dashboard IS 'Dashboard view showing consistency issue summary by type and severity';


