);


--
-- Name: content_source_analytics; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.content_source_analytics AS
 SELECT cs.id,
    cs.name,
    cs.type,
    cs.is_active,
    count(ic.id) AS total_content,
    count(
        CASE
            WHEN ((ic.status)::text = 'processed'::text) THEN 1
            ELSE NULL::integer
        END) AS processed_content,
    count(
        CASE
            WHEN ((ic.status)::text = 'pending'::text) THEN 1
            ELSE NULL::integer
        END) AS pending_content,
    count(
        CASE
            WHEN ((ic.status)::text = 'rejected'::text) THEN 1
            ELSE NULL::integer
        END) AS rejected_content,
    count(
        CASE
            WHEN ((ic.status)::text = 'duplicate'::text) THEN 1
            ELSE NULL::integer
        END) AS duplicate_content,
    max(ic.created_at) AS last_content_received
   FROM (public.content_sources cs
     LEFT JOIN public.ingested_content ic ON ((cs.id = ic.source_id)))
  GROUP BY cs.id, cs.name, cs.type, cs.is_active;


