--
-- Name: deprecated_tests; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.deprecated_tests AS
 SELECT test_metadata.test_id,
    test_metadata.file_path,
    test_metadata.test_name,
    test_metadata.test_type,
    test_metadata.dependencies,
    test_metadata.code_coverage,
    test_metadata.last_modified,
    test_metadata.last_executed,
    test_metadata.execution_count,
    test_metadata.failure_rate,
    test_metadata.average_runtime_ms,
    test_metadata.complexity,
    test_metadata.relationships,
    test_metadata.status,
    test_metadata.tags,
    test_metadata.annotations,
    test_metadata.created_at,
    test_metadata.updated_at
   FROM public.test_metadata
  WHERE ((test_metadata.status)::text = 'deprecated'::text);


--
-- Name: disaster_recovery_tests; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.disaster_recovery_tests (
    id bigint NOT NULL,
    test_name character varying(200) NOT NULL,
    backup_id bigint NOT NULL,
    test_type character varying(50) NOT NULL,
    status character varying(20) DEFAULT 'pending'::character varying NOT NULL,
    test_environment character varying(100),
    recovery_time bigint DEFAULT 0,
    data_integrity boolean DEFAULT false,
    test_results jsonb,
    started_at timestamp with time zone NOT NULL,
    completed_at timestamp with time zone,
    error_msg text,
    created_at timestamp with time zone DEFAULT now(),
    updated_at timestamp with time zone DEFAULT now(),
    CONSTRAINT disaster_recovery_tests_status_check CHECK (((status)::text = ANY ((ARRAY['pending'::character varying, 'running'::character varying, 'completed'::character varying, 'failed'::character varying])::text[])))
);


--
-- Name: TABLE disaster_recovery_tests; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON TABLE public.disaster_recovery_tests IS 'Disaster recovery test execution results';


