--
-- Name: test_reliability_metrics; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.test_reliability_metrics (
    test_name character varying(255) NOT NULL,
    test_suite character varying(255) NOT NULL,
    reliability_score double precision NOT NULL,
    flakiness_score double precision NOT NULL,
    stability_trend character varying(50),
    total_executions bigint DEFAULT 0,
    successful_executions bigint DEFAULT 0,
    failed_executions bigint DEFAULT 0,
    error_executions bigint DEFAULT 0,
    skipped_executions bigint DEFAULT 0,
    average_duration bigint DEFAULT 0,
    duration_variance double precision DEFAULT 0,
    failure_patterns jsonb,
    environment_impact jsonb,
    time_of_day_impact jsonb,
    recent_performance jsonb,
    last_updated timestamp without time zone DEFAULT now(),
    CONSTRAINT test_reliability_metrics_flakiness_score_check CHECK (((flakiness_score >= (0)::double precision) AND (flakiness_score <= (1)::double precision))),
    CONSTRAINT test_reliability_metrics_reliability_score_check CHECK (((reliability_score >= (0)::double precision) AND (reliability_score <= (1)::double precision))),
    CONSTRAINT test_reliability_metrics_stability_trend_check CHECK (((stability_trend)::text = ANY ((ARRAY['improving'::character varying, 'stable'::character varying, 'degrading'::character varying])::text[])))
);


--
-- Name: TABLE test_reliability_metrics; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON TABLE public.test_reliability_metrics IS 'Aggregated reliability metrics and analysis for each test';


--
-- Name: flaky_tests_summary; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.flaky_tests_summary AS
 SELECT trm.test_name,
    trm.test_suite,
    trm.flakiness_score,
    trm.reliability_score,
    trm.stability_trend,
    trm.total_executions,
    trm.failed_executions,
        CASE
            WHEN ((tq.status)::text = 'quarantined'::text) THEN 'quarantined'::text
            WHEN (trm.flakiness_score > (0.5)::double precision) THEN 'critical'::text
            WHEN (trm.flakiness_score > (0.3)::double precision) THEN 'warning'::text
            ELSE 'stable'::text
        END AS status,
    tq.quarantined_at,
    trm.last_updated
   FROM (public.test_reliability_metrics trm
     LEFT JOIN public.test_quarantine tq ON ((((trm.test_name)::text = (tq.test_name)::text) AND ((trm.test_suite)::text = (tq.test_suite)::text))))
  WHERE (trm.flakiness_score > (0.1)::double precision)
  ORDER BY trm.flakiness_score DESC;


--
-- Name: VIEW flaky_tests_summary; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON VIEW public.flaky_tests_summary IS 'Summary view of flaky tests with status classification';


