--
-- Name: latest_cache_metrics; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.latest_cache_metrics AS
 SELECT DISTINCT ON ((date_trunc('hour'::text, cache_metrics.created_at))) cache_metrics.id,
    cache_metrics.hit_count,
    cache_metrics.miss_count,
    cache_metrics.hit_rate,
    cache_metrics.key_count,
    cache_metrics.memory_usage,
    cache_metrics.memory_total,
    cache_metrics.evicted_keys,
    cache_metrics.expired_keys,
    cache_metrics.operations_per_sec,
    cache_metrics.average_latency,
    cache_metrics.created_at
   FROM public.cache_metrics
  WHERE (cache_metrics.created_at >= (now() - '24:00:00'::interval))
  ORDER BY (date_trunc('hour'::text, cache_metrics.created_at)) DESC, cache_metrics.created_at DESC;


