    database_metrics.max_connections,
    database_metrics.slow_queries,
    database_metrics.average_query_time,
    database_metrics.queries_per_second,
    database_metrics.cache_hit_ratio,
    database_metrics.deadlock_count,
    database_metrics.temp_files_created,
    database_metrics.checkpoint_write_time,
    database_metrics.created_at
   FROM public.database_metrics
  WHERE (database_metrics.created_at >= (now() - '24:00:00'::interval))
  ORDER BY (date_trunc('hour'::text, database_metrics.created_at)) DESC, database_metrics.created_at DESC;


