--
-- Name: pending_canonical_jobs; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.pending_canonical_jobs AS
 SELECT cj.id,
    cj.article_id,
    cj.target_type,
    cj.target_id,
    cj.target_url,
    cj.scheduled_at,
    cj.processed_at,
    cj.status,
    cj.admin_override,
    cj.created_by,
    cj.processed_by,
    cj.error_message,
    cj.retry_count,
    cj.created_at,
    cj.updated_at,
    a.title AS article_title,
    a.slug AS article_slug,
        CASE
            WHEN ((cj.target_type)::text = 'tag'::text) THEN t.name
            WHEN ((cj.target_type)::text = 'category'::text) THEN c.name
            ELSE NULL::character varying
        END AS target_name,
        CASE
            WHEN ((cj.target_type)::text = 'tag'::text) THEN t.slug
            WHEN ((cj.target_type)::text = 'category'::text) THEN c.slug
            ELSE NULL::character varying
        END AS target_slug
   FROM (((public.canonical_jobs cj
     LEFT JOIN public.articles a ON ((cj.article_id = a.id)))
     LEFT JOIN public.tags t ON ((((cj.target_type)::text = 'tag'::text) AND (cj.target_id = t.id))))
     LEFT JOIN public.categories c ON ((((cj.target_type)::text = 'category'::text) AND (cj.target_id = c.id))))
  WHERE (((cj.status)::text = 'pending'::text) AND ((cj.admin_override = true) OR (cj.scheduled_at <= now())))
  ORDER BY cj.admin_override DESC, cj.scheduled_at;


