    CONSTRAINT performance_alerts_alert_type_check CHECK (((alert_type)::text = ANY ((ARRAY['regression'::character varying, 'improvement'::character varying, 'trend'::character varying, 'threshold'::character varying])::text[]))),
    CONSTRAINT performance_alerts_severity_check CHECK (((severity)::text = ANY ((ARRAY['critical'::character varying, 'high'::character varying, 'medium'::character varying, 'low'::character varying, 'info'::character varying])::text[])))
);


