--
-- Name: performance_metrics_trends; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.performance_metrics_trends AS
 SELECT integration_metrics.component,
    integration_metrics.metric_name,
    date_trunc('hour'::text, integration_metrics.recorded_at) AS hour,
    avg(integration_metrics.metric_value) AS avg_value,
    min(integration_metrics.metric_value) AS min_value,
    max(integration_metrics.metric_value) AS max_value,
    count(*) AS sample_count
   FROM public.integration_metrics
  WHERE (integration_metrics.recorded_at >= (now() - '24:00:00'::interval))
  GROUP BY integration_metrics.component, integration_metrics.metric_name, (date_trunc('hour'::text, integration_metrics.recorded_at))
  ORDER BY integration_metrics.component, integration_metrics.metric_name, (date_trunc('hour'::text, integration_metrics.recorded_at));


--
-- Name: VIEW performance_metrics_trends; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON VIEW public.performance_metrics_trends IS 'Shows performance metrics trends over time';


