--

CREATE TABLE public.performance_regression_results (
    id bigint NOT NULL,
    test_name character varying(255) NOT NULL,
    current_version character varying(100) NOT NULL,
    baseline_version character varying(100) NOT NULL,
    result_data jsonb NOT NULL,
    overall_status character varying(20) NOT NULL,
    overall_score numeric(5,2) DEFAULT 0.00 NOT NULL,
    compared_at timestamp with time zone DEFAULT now() NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT performance_regression_results_overall_score_check CHECK (((overall_score >= (0)::numeric) AND (overall_score <= (100)::numeric))),
    CONSTRAINT performance_regression_results_overall_status_check CHECK (((overall_status)::text = ANY ((ARRAY['pass'::character varying, 'warning'::character varying, 'fail'::character varying, 'critical'::character varying])::text[])))
);


