    automated_result_id bigint NOT NULL,
    metric_name character varying(255) NOT NULL,
    trend_direction character varying(50) NOT NULL,
    trend_strength numeric(5,4) NOT NULL,
    predicted_value numeric(15,6) NOT NULL,
    confidence_lower numeric(15,6) NOT NULL,
    confidence_upper numeric(15,6) NOT NULL,
    confidence_level numeric(5,4) DEFAULT 0.95 NOT NULL,
    forecast_accuracy numeric(5,4) DEFAULT 0.8 NOT NULL,
    forecast_timestamp timestamp with time zone NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT performance_trend_forecasts_trend_direction_check CHECK (((trend_direction)::text = ANY ((ARRAY['increasing'::character varying, 'decreasing'::character varying, 'stable'::character varying])::text[]))),
    CONSTRAINT performance_trend_forecasts_trend_strength_check CHECK (((trend_strength >= (0)::numeric) AND (trend_strength <= (1)::numeric)))
);


