-- Name: remediation_executions; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.remediation_executions (
    id bigint NOT NULL,
    action_id character varying(255) NOT NULL,
    alert_name character varying(255) NOT NULL,
    status character varying(20) NOT NULL,
    started_at timestamp with time zone NOT NULL,
    completed_at timestamp with time zone,
    output text,
    error text,
    metadata jsonb DEFAULT '{}'::jsonb,
    created_at timestamp with time zone DEFAULT now(),
    CONSTRAINT remediation_executions_status_check CHECK (((status)::text = ANY ((ARRAY['pending'::character varying, 'running'::character varying, 'completed'::character varying, 'failed'::character varying, 'skipped'::character varying])::text[])))
);


--
-- Name: recent_remediation_executions; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.recent_remediation_executions AS
 SELECT remediation_executions.id,
    remediation_executions.action_id,
    remediation_executions.alert_name,
    remediation_executions.status,
    remediation_executions.started_at,
    remediation_executions.completed_at,
    remediation_executions.output,
    remediation_executions.error,
    remediation_executions.metadata,
    remediation_executions.created_at
   FROM public.remediation_executions
  WHERE (remediation_executions.created_at >= (CURRENT_DATE - '7 days'::interval))
  ORDER BY remediation_executions.created_at DESC;


--
-- Name: runbook_executions; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.runbook_executions (
    id bigint NOT NULL,
    runbook_id character varying(255) NOT NULL,
    alert_name character varying(255) NOT NULL,
    status character varying(20) NOT NULL,
    started_at timestamp with time zone NOT NULL,
    completed_at timestamp with time zone,
    step_results jsonb DEFAULT '[]'::jsonb,
    metadata jsonb DEFAULT '{}'::jsonb,
    created_at timestamp with time zone DEFAULT now(),
    CONSTRAINT runbook_executions_status_check CHECK (((status)::text = ANY ((ARRAY['pending'::character varying, 'running'::character varying, 'completed'::character varying, 'failed'::character varying, 'paused'::character varying])::text[])))
);


--
-- Name: recent_runbook_executions; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.recent_runbook_executions AS
 SELECT runbook_executions.id,
    runbook_executions.runbook_id,
    runbook_executions.alert_name,
    runbook_executions.status,
    runbook_executions.started_at,
    runbook_executions.completed_at,
    runbook_executions.step_results,
    runbook_executions.metadata,
    runbook_executions.created_at
   FROM public.runbook_executions
  WHERE (runbook_executions.created_at >= (CURRENT_DATE - '7 days'::interval))
  ORDER BY runbook_executions.created_at DESC;


--
-- Name: recent_test_executions; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.recent_test_executions AS
 SELECT enhanced_test_results.execution_id,
    enhanced_test_results.status,
    enhanced_test_results.start_time,
    enhanced_test_results.end_time,
    ((enhanced_test_results.duration)::numeric / 1000000000.0) AS duration_seconds,
    ((enhanced_test_results.result_data ->> 'test_results'::text))::jsonb AS test_results_summary,
    enhanced_test_results.created_at
   FROM public.enhanced_test_results
  WHERE (enhanced_test_results.start_time >= (now() - '7 days'::interval))
  ORDER BY enhanced_test_results.start_time DESC;


--
-- Name: VIEW recent_test_executions; Type: COMMENT; Schema: public; Owner: -
