)
PARTITION BY RANGE (created_at);


--
-- Name: system_health_summary; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.system_health_summary AS
 SELECT 'system'::text AS component,
        CASE
            WHEN ((system_metrics_history.cpu_usage >= (85)::numeric) OR (system_metrics_history.memory_usage >= (90)::numeric) OR (system_metrics_history.disk_usage >= (95)::numeric)) THEN 'unhealthy'::text
            WHEN ((system_metrics_history.cpu_usage >= (70)::numeric) OR (system_metrics_history.memory_usage >= (80)::numeric) OR (system_metrics_history.disk_usage >= (85)::numeric)) THEN 'degraded'::text
            ELSE 'healthy'::text
        END AS status,
    system_metrics_history.cpu_usage,
    system_metrics_history.memory_usage,
    system_metrics_history.disk_usage,
    system_metrics_history.created_at
   FROM public.system_metrics_history
  WHERE (system_metrics_history.created_at >= (now() - '00:05:00'::interval))
  ORDER BY system_metrics_history.created_at DESC
 LIMIT 1;


