--
-- Name: tag_translations; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.tag_translations AS
 SELECT t.id,
    t.name,
    t.slug,
    t.language_code,
    t.translation_group_id,
    t.keywords,
    t.color,
    l.name AS language_name,
    l.native_name AS language_native_name,
    l.direction AS language_direction,
    array_agg(json_build_object('id', tt.id, 'name', tt.name, 'slug', tt.slug, 'language_code', tt.language_code, 'language_name', tl.name, 'language_native_name', tl.native_name) ORDER BY tl.sort_order) FILTER (WHERE (tt.id <> t.id)) AS translations
   FROM ((((public.tags t
     LEFT JOIN public.translation_groups tg ON ((t.translation_group_id = tg.id)))
     LEFT JOIN public.languages l ON (((t.language_code)::text = (l.code)::text)))
     LEFT JOIN public.tags tt ON ((t.translation_group_id = tt.translation_group_id)))
     LEFT JOIN public.languages tl ON (((tt.language_code)::text = (tl.code)::text)))
  GROUP BY t.id, t.name, t.slug, t.language_code, t.translation_group_id, t.keywords, t.color, l.name, l.native_name, l.direction;


--
-- Name: VIEW tag_translations; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON VIEW public.tag_translations IS 'Tags with their available translations';


