 SELECT test_relationships.source_test_id,
    test_relationships.relation_type,
    count(*) AS relationship_count,
    avg(test_relationships.strength) AS avg_strength
   FROM public.test_relationships
  GROUP BY test_relationships.source_test_id, test_relationships.relation_type;


